package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.math.BigDecimal;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonPrimitiveTest {

  private JsonPrimitive jsonPrimitive;

  @BeforeEach
  void setup() {
    // no-op, will create instances per test
  }

  @Test
  void getAsBigDecimal_whenValueIsBigDecimal_returnsValueDirectly() throws Exception {
    BigDecimal bd = new BigDecimal("123.45");
    jsonPrimitive = createJsonPrimitiveWithValue(bd);

    BigDecimal result = jsonPrimitive.getAsBigDecimal();

    assertSame(bd, result);
  }

  @Test
  void getAsBigDecimal_whenValueIsString_returnsBigDecimalFromString() throws Exception {
    String numberString = "6789.01";
    jsonPrimitive = createJsonPrimitiveWithValue(numberString);

    BigDecimal result = jsonPrimitive.getAsBigDecimal();

    assertEquals(new BigDecimal(numberString), result);
  }

  @Test
  void getAsBigDecimal_whenValueIsLazilyParsedNumber_returnsBigDecimalFromString() throws Exception {
    LazilyParsedNumber lpn = new LazilyParsedNumber("9876.54");
    jsonPrimitive = createJsonPrimitiveWithValue(lpn);

    BigDecimal result = jsonPrimitive.getAsBigDecimal();

    assertEquals(new BigDecimal("9876.54"), result);
  }

  // Helper method to create JsonPrimitive and inject private final value field via reflection
  private JsonPrimitive createJsonPrimitiveWithValue(Object value) throws Exception {
    JsonPrimitive instance = mock(JsonPrimitive.class, withSettings().useConstructor().defaultAnswer(CALLS_REAL_METHODS));
    Field valueField = JsonPrimitive.class.getDeclaredField("value");
    valueField.setAccessible(true);
    valueField.set(instance, value);
    return instance;
  }
}
